<?php include "db.php"; include "helpers.php"; $id=intval($_GET['id']??0); $stmt=$conn->prepare("SELECT * FROM lesson_plans WHERE id=?"); $stmt->bind_param('i',$id); $stmt->execute(); $row=$stmt->get_result()->fetch_assoc(); if(!$row)die('Lesson not found'); function opt($items,$sel){$h='';foreach($items as $i){$h.='<option value="'.out($i).'" '.($i==$sel?'selected':'').'>'.out($i).'</option>'; }return$h;} ?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Edit Lesson Plan</title><link rel="stylesheet" href="style.css"></head><body><div class="container"><h1>Edit Lesson Plan</h1><form method="POST" action="update.php"><input type="hidden" name="id" value="<?php echo $row['id']; ?>"><div class="grid-2"><div><label>Teacher Name</label><input name="teacher" value="<?php echo out($row['teacher']); ?>" required></div><div><label>School</label><input name="school" value="<?php echo out($row['school']); ?>" required></div></div><div class="grid-2"><div><label>Grade Level and Section</label><input name="grade_level" value="<?php echo out($row['grade_level']); ?>" required></div><div><label>Learning Area/s</label><input name="subject" value="<?php echo out($row['subject']); ?>" required></div></div><label>Subject Color</label><input type="color" name="subject_color" value="<?php echo out($row['subject_color'] ?: '#dbeafe'); ?>"><input type="hidden" name="plan_type" value="DepEd 2026 Appendix A Lesson Plan"><label>Curriculum</label><select name="curriculum" required><?php echo opt(['K–10 MATATAG Curriculum','Strengthened Senior High School Curriculum','Existing Senior High School Curriculum'],$row['curriculum']); ?></select><div class="grid-2"><div><label>Term</label><select name="term" required><?php echo opt(['Term 1','Term 2','Term 3'],$row['term']); ?></select></div><div><label>Week / Day</label><input name="week_day" value="<?php echo out($row['week_day']); ?>" required></div></div><div class="grid-2"><div><label>Lesson Date</label><input type="date" name="lesson_date" value="<?php echo out($row['lesson_date']); ?>" required></div><div><label>Duration</label><input name="duration" value="<?php echo out($row['duration']); ?>" required></div></div><label>No. of Sessions</label><input name="no_sessions" value="<?php echo out($row['no_sessions']); ?>" required><label>References</label><textarea name="references_used"><?php echo out($row['references_used']); ?></textarea><label>Declaration of AI Use</label><textarea name="declaration_ai_use"><?php echo out($row['declaration_ai_use']); ?></textarea><label>Name of Lesson / Topic</label><input name="topic" value="<?php echo out($row['topic']); ?>" required><label>Content Standards</label><textarea name="content_standards"><?php echo out($row['content_standards']); ?></textarea><label>Performance Standards</label><textarea name="performance_standards"><?php echo out($row['performance_standards']); ?></textarea><label>Learning Competency</label><textarea name="competency" required><?php echo out($row['competency']); ?></textarea><label>Learning Objectives</label><textarea name="objectives" required><?php echo out($row['objectives']); ?></textarea><label>Learner Context</label><textarea name="learner_context"><?php echo out($row['learner_context']); ?></textarea><label>Pre-Lesson</label><textarea name="pre_lesson"><?php echo out($row['pre_lesson']); ?></textarea><label>Flow</label><textarea name="lesson_flow"><?php echo out($row['lesson_flow']); ?></textarea><label>Learning Resources</label><textarea name="materials"><?php echo out($row['materials']); ?></textarea><label>Opportunities for Integration</label><textarea name="integration"><?php echo out($row['integration']); ?></textarea><label>Class Profile / Notes</label><textarea name="class_profile"><?php echo out($row['class_profile']); ?></textarea><label>Language of Instruction</label><select name="language_instruction"><?php echo opt(['','English','Filipino','Mother Tongue','Bilingual'],$row['language_instruction']); ?></select><label>Formative Assessment</label><textarea name="assessment"><?php echo out($row['assessment']); ?></textarea><label>Remarks</label><textarea name="remarks"><?php echo out($row['remarks']); ?></textarea><label>Extended Learning Opportunities</label><textarea name="extended_learning"><?php echo out($row['extended_learning']); ?></textarea><label>Reflections</label><textarea name="reflection"><?php echo out($row['reflection']); ?></textarea><input type="submit" value="Update and Regenerate"><a href="view.php?id=<?php echo $row['id']; ?>">Cancel</a></form></div></body></html>
